<?php
require_once __DIR__.'/functions.php'; require_once __DIR__.'/mail.php'; $member=require_member(false);
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=(string)($_POST['action']??'save');try{if($action==='resend'){send_verification_email($member);flash('Te enviamos un enlace nuevo.');redirect('/profile.php');}$name=trim((string)($_POST['display_name']??''));$bio=trim((string)($_POST['bio']??''));if(mb_strlen($name)<2||mb_strlen($bio)>500)throw new RuntimeException('Revisa el nombre y la biografía.');$avatar=upload_avatar($_FILES['avatar']??[]);$sql='UPDATE members SET display_name=?,bio=?'.($avatar?',avatar=?':'').' WHERE id=?';$args=[$name,$bio];if($avatar)$args[]=$avatar;$args[]=$member['id'];db()->prepare($sql)->execute($args);if($avatar)delete_image($member['avatar']??null);flash('Perfil actualizado.');redirect('/profile.php');}catch(Throwable $e){flash($e->getMessage(),'error');}}
render_header('Mi perfil',['robots'=>'noindex,nofollow']);?><section class="panel narrow"><div class="profile-head"><?php if($member['avatar']):?><img class="avatar avatar-lg" src="/uploads/<?=e($member['avatar'])?>" alt=""><?php else:?><span class="avatar avatar-lg avatar-fallback"><?=e(mb_strtoupper(mb_substr($member['display_name'],0,1)))?></span><?php endif;?><div><h1>Mi perfil</h1><p class="muted"><?=e($member['email'])?></p></div></div><?php if(empty($member['email_verified_at'])):?><div class="verification-box"><strong>Correo pendiente de verificación</strong><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="action" value="resend"><button class="button">Reenviar enlace</button></form></div><?php else:?><p class="verified">✓ Correo verificado</p><?php endif;?><form method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><label>Nombre visible<input name="display_name" maxlength="80" value="<?=e($member['display_name'])?>" required></label><label>Biografía<textarea name="bio" maxlength="500" rows="4"><?=e($member['bio'])?></textarea></label><label>Avatar (máximo 2 MB)<input type="file" name="avatar" accept="image/png,image/jpeg,image/gif,image/webp"></label><button class="button">Guardar perfil</button></form></section><?php render_footer();
